fn hash_password(pw: &str) -> String {
    argon2id(pw, MemoryKiB(65536), Iterations(3))
}

fn new_session_id() -> String {
    base64url(random_bytes(32))
}

fn max_of(a: i64, b: i64) -> i64 {
    if a > b { a } else { b }
}

fn is_even(n: i64) -> bool {
    n % 2 == 0
}

export function statusForCreate() {
  return 201;
}

export function notFoundResponse(res) {
  return res.status(404).json({ error: "not found" });
}

export function rateLimited(res, retryAfter) {
  return res.status(429).set("Retry-After", retryAfter).end();
}

export function parseBool(s) {
  return s === "true" || s === "1";
}
